// About code: This code for The auxObserver class is a custom JavaScript utility designed to track when specific sections of a webpage enter or exit the viewport. It acts similarly to the native IntersectionObserver API but gives more fine-grained manual control by using scroll positions, offsets, and optional debugging visuals.


class auxObserver{constructor({secId:t,offset:{scrollOffset:e,xOffset:o,yOffset:s}={},viewport:{onEnter:r,onExit:l},graphs:f=!1}){this.secId=t,this.scrollOffset=e,this.xOffset=o,this.yOffset=s;let p=document.querySelectorAll(t);p.forEach(t=>{let p={inViewport:!1,outViewport:!1},i=e||0,c=o||0,n=s||0,y=0+i,a=t.offsetTop+c,u=t.offsetTop+t.offsetHeight-n,d=!1;if(window.addEventListener("scroll",()=>{y=Math.floor(window.scrollY)+i,a=t.offsetTop+c,u=t.offsetTop+t.offsetHeight-n}),window.addEventListener("scroll",()=>{let e=y>=a&&y<=u;p.inViewport=e,p.outViewport=!e,e!==d&&(p.inViewport&&r&&r(t),p.outViewport&&l&&l(t)),d=e}),f){var x=t.querySelector(".scrollMark"),h=t.querySelector(".secStart"),w=t.querySelector(".secEnd");x.style.top=y+"px",h.style.top=a+"px",w.style.top=u+"px",window.addEventListener("scroll",()=>{x.style.top=y+"px",h.style.top=a+"px",w.style.top=u+"px"})}})}}